import{_ as a,o,c as d,ae as t}from"./chunks/framework.BEtfQoF7.js";const p=JSON.parse('{"title":"Claude Code 작동 방식","description":"에이전틱 루프, 내장 도구, Claude Code가 프로젝트와 상호 작용하는 방식을 이해하세요.","frontmatter":{"title":"Claude Code 작동 방식","description":"에이전틱 루프, 내장 도구, Claude Code가 프로젝트와 상호 작용하는 방식을 이해하세요."},"headers":[],"relativePath":"how-claude-code-works.md","filePath":"how-claude-code-works.md","lastUpdated":1776205703000}'),l={name:"how-claude-code-works.md"};function s(c,e,r,i,n,h){return o(),d("div",null,[...e[0]||(e[0]=[t(`<h1 id="claude-code-작동-방식" tabindex="-1">Claude Code 작동 방식 <a class="header-anchor" href="#claude-code-작동-방식" aria-label="Permalink to &quot;Claude Code 작동 방식&quot;">​</a></h1><p>Claude Code는 터미널에서 실행되는 에이전틱 어시스턴트입니다. 코딩에 뛰어나지만, 명령줄에서 할 수 있는 모든 작업을 도울 수 있습니다: 문서 작성, 빌드 실행, 파일 검색, 주제 조사 등.</p><p>이 가이드에서는 핵심 아키텍처, 내장 기능, <a href="#claude-code와-효과적으로-작업하기">Claude Code와 효과적으로 작업하는 팁</a>을 다룹니다. 단계별 안내는 <a href="/claude-code-docs-ko/common-workflows.html">일반적인 워크플로우</a>를 참조하세요. skills, MCP, hooks 같은 확장 기능은 <a href="/claude-code-docs-ko/features-overview.html">Claude Code 확장하기</a>를 참조하세요.</p><h2 id="에이전틱-루프" tabindex="-1">에이전틱 루프 <a class="header-anchor" href="#에이전틱-루프" aria-label="Permalink to &quot;에이전틱 루프&quot;">​</a></h2><p>Claude에 작업을 부여하면 세 단계를 거칩니다: <strong>컨텍스트 수집</strong>, <strong>작업 수행</strong>, <strong>결과 확인</strong>. 이 단계들은 서로 융합됩니다. Claude는 코드를 이해하기 위해 파일을 검색하거나, 변경을 위해 편집하거나, 작업을 확인하기 위해 테스트를 실행할 때 전체적으로 도구를 사용합니다.</p><p>루프는 요청에 따라 적응합니다. 코드베이스에 대한 질문은 컨텍스트 수집만 필요할 수 있습니다. 버그 수정은 세 단계를 반복적으로 순환합니다. 리팩토링은 광범위한 검증을 포함할 수 있습니다. Claude는 이전 단계에서 학습한 내용을 바탕으로 각 단계에 필요한 것을 결정하며, 수십 개의 작업을 연결하고 경로를 수정합니다.</p><p>여러분도 이 루프의 일부입니다. 언제든지 중단하여 Claude를 다른 방향으로 안내하거나, 추가 컨텍스트를 제공하거나, 다른 접근 방식을 시도하도록 요청할 수 있습니다. Claude는 자율적으로 작업하지만 여러분의 입력에 반응합니다.</p><p>에이전틱 루프는 두 가지 구성 요소로 구동됩니다: 추론하는 <a href="#모델">모델</a>과 행동하는 <a href="#도구">도구</a>. Claude Code는 Claude 주위의 <strong>에이전틱 하네스</strong> 역할을 합니다: 언어 모델을 유능한 코딩 에이전트로 변환하는 도구, 컨텍스트 관리, 실행 환경을 제공합니다.</p><h3 id="모델" tabindex="-1">모델 <a class="header-anchor" href="#모델" aria-label="Permalink to &quot;모델&quot;">​</a></h3><p>Claude Code는 Claude 모델을 사용하여 코드를 이해하고 작업에 대해 추론합니다. Claude는 모든 언어의 코드를 읽고, 구성 요소가 어떻게 연결되는지 이해하며, 목표를 달성하기 위해 무엇을 변경해야 하는지 파악할 수 있습니다. 복잡한 작업의 경우 작업을 단계로 나누고 실행하며 학습한 내용에 따라 조정합니다.</p><p>다양한 트레이드오프를 가진 <a href="/claude-code-docs-ko/model-config.html">여러 모델</a>을 사용할 수 있습니다. Sonnet은 대부분의 코딩 작업을 잘 처리합니다. Opus는 복잡한 아키텍처 결정에 더 강력한 추론을 제공합니다. 세션 중 <code>/model</code>로 전환하거나 <code>claude --model &lt;name&gt;</code>으로 시작하세요.</p><p>이 가이드에서 &quot;Claude가 선택한다&quot; 또는 &quot;Claude가 결정한다&quot;라고 할 때, 추론을 수행하는 것은 모델입니다.</p><h3 id="도구" tabindex="-1">도구 <a class="header-anchor" href="#도구" aria-label="Permalink to &quot;도구&quot;">​</a></h3><p>도구는 Claude Code를 에이전틱하게 만드는 요소입니다. 도구 없이 Claude는 텍스트로만 응답할 수 있습니다. 도구가 있으면 Claude는 행동할 수 있습니다: 코드를 읽고, 파일을 편집하고, 명령을 실행하고, 웹을 검색하고, 외부 서비스와 상호 작용합니다. 각 도구 사용은 루프에 피드백되는 정보를 반환하여 Claude의 다음 결정에 영향을 줍니다.</p><p>내장 도구는 일반적으로 다섯 가지 범주로 나뉩니다.</p><table tabindex="0"><thead><tr><th>범주</th><th>Claude가 할 수 있는 것</th></tr></thead><tbody><tr><td><strong>파일 작업</strong></td><td>파일 읽기, 코드 편집, 새 파일 생성, 이름 변경 및 재구성</td></tr><tr><td><strong>검색</strong></td><td>패턴으로 파일 찾기, 정규식으로 내용 검색, 코드베이스 탐색</td></tr><tr><td><strong>실행</strong></td><td>셸 명령 실행, 서버 시작, 테스트 실행, git 사용</td></tr><tr><td><strong>웹</strong></td><td>웹 검색, 문서 가져오기, 오류 메시지 조회</td></tr><tr><td><strong>코드 인텔리전스</strong></td><td>편집 후 타입 오류 및 경고 확인, 정의로 이동, 참조 찾기 (<a href="/claude-code-docs-ko/discover-plugins.html#code-intelligence">코드 인텔리전스 플러그인</a> 필요)</td></tr></tbody></table><p>이것이 주요 기능입니다. Claude에는 하위 에이전트 생성, 질문하기 및 기타 오케스트레이션 작업을 위한 도구도 있습니다. 전체 목록은 <a href="/claude-code-docs-ko/tools-reference.html">Claude에서 사용 가능한 도구</a>를 참조하세요.</p><p>Claude는 프롬프트와 진행 과정에서 학습한 내용을 바탕으로 사용할 도구를 선택합니다. &quot;실패하는 테스트를 수정하세요&quot;라고 하면 Claude는 다음과 같이 할 수 있습니다:</p><ol><li>테스트 스위트를 실행하여 무엇이 실패하는지 확인</li><li>오류 출력 읽기</li><li>관련 소스 파일 검색</li><li>해당 파일을 읽어 코드 이해</li><li>문제를 수정하기 위해 파일 편집</li><li>테스트를 다시 실행하여 확인</li></ol><p>각 도구 사용은 다음 단계에 영향을 주는 새로운 정보를 Claude에 제공합니다. 이것이 에이전틱 루프의 실제 동작입니다.</p><p><strong>기본 기능 확장:</strong> 내장 도구가 기반입니다. <a href="/claude-code-docs-ko/skills.html">skills</a>로 Claude가 아는 것을 확장하고, <a href="/claude-code-docs-ko/mcp.html">MCP</a>로 외부 서비스에 연결하고, <a href="/claude-code-docs-ko/hooks.html">hooks</a>로 워크플로우를 자동화하고, <a href="/claude-code-docs-ko/sub-agents.html">하위 에이전트</a>에 작업을 위임할 수 있습니다. 이러한 확장 기능은 핵심 에이전틱 루프 위의 레이어를 형성합니다. 필요에 맞는 확장 기능 선택에 대한 안내는 <a href="/claude-code-docs-ko/features-overview.html">Claude Code 확장하기</a>를 참조하세요.</p><h2 id="claude가-접근할-수-있는-것" tabindex="-1">Claude가 접근할 수 있는 것 <a class="header-anchor" href="#claude가-접근할-수-있는-것" aria-label="Permalink to &quot;Claude가 접근할 수 있는 것&quot;">​</a></h2><p>이 가이드는 터미널에 초점을 맞춥니다. Claude Code는 <a href="/claude-code-docs-ko/vs-code.html">VS Code</a>, <a href="/claude-code-docs-ko/jetbrains.html">JetBrains IDE</a> 및 기타 환경에서도 실행됩니다.</p><p>디렉토리에서 <code>claude</code>를 실행하면 Claude Code가 다음에 접근할 수 있습니다:</p><ul><li><strong>프로젝트.</strong> 디렉토리와 하위 디렉토리의 파일, 그리고 여러분의 허가 하에 다른 곳의 파일.</li><li><strong>터미널.</strong> 실행할 수 있는 모든 명령: 빌드 도구, git, 패키지 관리자, 시스템 유틸리티, 스크립트. 명령줄에서 할 수 있는 것이라면 Claude도 할 수 있습니다.</li><li><strong>git 상태.</strong> 현재 브랜치, 커밋되지 않은 변경 사항, 최근 커밋 이력.</li><li><strong><a href="/claude-code-docs-ko/memory.html">CLAUDE.md</a>.</strong> 프로젝트별 지침, 규칙, Claude가 매 세션마다 알아야 할 컨텍스트를 저장하는 마크다운 파일.</li><li><strong><a href="/claude-code-docs-ko/memory.html#auto-memory">Auto memory</a>.</strong> Claude가 프로젝트 패턴과 여러분의 선호도 같이 작업하면서 자동으로 저장하는 학습 내용. MEMORY.md의 처음 200줄 또는 25KB(먼저 도달하는 것)가 각 세션 시작 시 로드됩니다.</li><li><strong>구성한 확장 기능.</strong> 외부 서비스를 위한 <a href="/claude-code-docs-ko/mcp.html">MCP 서버</a>, 워크플로우를 위한 <a href="/claude-code-docs-ko/skills.html">skills</a>, 위임 작업을 위한 <a href="/claude-code-docs-ko/sub-agents.html">하위 에이전트</a>, 브라우저 상호 작용을 위한 <a href="/claude-code-docs-ko/chrome.html">Chrome의 Claude</a>.</li></ul><p>Claude는 전체 프로젝트를 보기 때문에 프로젝트 전반에 걸쳐 작업할 수 있습니다. &quot;인증 버그를 수정해줘&quot;라고 요청하면, 관련 파일을 검색하고, 컨텍스트를 이해하기 위해 여러 파일을 읽고, 파일 간 조율된 편집을 하고, 수정을 확인하기 위해 테스트를 실행하고, 요청하면 변경 사항을 커밋합니다. 이는 현재 파일만 보는 인라인 코드 어시스턴트와 다릅니다.</p><h2 id="환경-및-인터페이스" tabindex="-1">환경 및 인터페이스 <a class="header-anchor" href="#환경-및-인터페이스" aria-label="Permalink to &quot;환경 및 인터페이스&quot;">​</a></h2><p>위에서 설명한 에이전틱 루프, 도구, 기능은 Claude Code를 사용하는 모든 곳에서 동일합니다. 변경되는 것은 코드가 실행되는 위치와 상호 작용 방식입니다.</p><h3 id="실행-환경" tabindex="-1">실행 환경 <a class="header-anchor" href="#실행-환경" aria-label="Permalink to &quot;실행 환경&quot;">​</a></h3><p>Claude Code는 세 가지 환경에서 실행되며, 각각 코드 실행 위치에 대한 트레이드오프가 다릅니다.</p><table tabindex="0"><thead><tr><th>환경</th><th>코드 실행 위치</th><th>사용 사례</th></tr></thead><tbody><tr><td><strong>로컬</strong></td><td>여러분의 머신</td><td>기본. 파일, 도구, 환경에 대한 전체 접근</td></tr><tr><td><strong>클라우드</strong></td><td>Anthropic 관리 VM</td><td>작업 오프로드, 로컬에 없는 레포에서 작업</td></tr><tr><td><strong>원격 제어</strong></td><td>여러분의 머신, 브라우저에서 제어</td><td>모든 것을 로컬에 유지하면서 웹 UI 사용</td></tr></tbody></table><h3 id="인터페이스" tabindex="-1">인터페이스 <a class="header-anchor" href="#인터페이스" aria-label="Permalink to &quot;인터페이스&quot;">​</a></h3><p>터미널, <a href="/claude-code-docs-ko/desktop.html">데스크톱 앱</a>, <a href="/claude-code-docs-ko/vs-code.html">IDE 확장</a>, <a href="https://claude.ai/code" target="_blank" rel="noreferrer">claude.ai/code</a>, <a href="/claude-code-docs-ko/remote-control.html">원격 제어</a>, <a href="/claude-code-docs-ko/slack.html">Slack</a>, <a href="/claude-code-docs-ko/github-actions.html">CI/CD 파이프라인</a>을 통해 Claude Code에 접근할 수 있습니다. 인터페이스에 따라 Claude를 보고 상호 작용하는 방식이 결정되지만, 기본 에이전틱 루프는 동일합니다. 전체 목록은 <a href="/claude-code-docs-ko/overview.html#use-claude-code-everywhere">어디서나 Claude Code 사용하기</a>를 참조하세요.</p><h2 id="세션-작업" tabindex="-1">세션 작업 <a class="header-anchor" href="#세션-작업" aria-label="Permalink to &quot;세션 작업&quot;">​</a></h2><p>Claude Code는 작업하면서 대화를 로컬에 저장합니다. 모든 메시지, 도구 사용, 결과는 <code>~/.claude/projects/</code> 아래의 일반 텍스트 JSONL 파일에 기록되며, 세션 <a href="#체크포인트로-변경-사항-취소">되감기</a>, <a href="#세션-재개-또는-포크">재개 및 포크</a>가 가능합니다. Claude가 코드를 변경하기 전에 영향을 받는 파일의 스냅샷도 만들어 필요시 되돌릴 수 있습니다. 경로, 보존 기간, 데이터 삭제 방법은 <a href="/claude-code-docs-ko/claude-directory.html#application-data"><code>~/.claude</code>의 애플리케이션 데이터</a>를 참조하세요.</p><p><strong>세션은 독립적입니다.</strong> 각 새 세션은 이전 세션의 대화 이력 없이 새로운 컨텍스트 윈도우로 시작합니다. Claude는 <a href="/claude-code-docs-ko/memory.html#auto-memory">auto memory</a>를 사용하여 세션 간 학습을 유지할 수 있으며, <a href="/claude-code-docs-ko/memory.html">CLAUDE.md</a>에 영구 지침을 추가할 수 있습니다.</p><h3 id="브랜치-간-작업" tabindex="-1">브랜치 간 작업 <a class="header-anchor" href="#브랜치-간-작업" aria-label="Permalink to &quot;브랜치 간 작업&quot;">​</a></h3><p>각 Claude Code 대화는 현재 디렉토리에 연결된 세션입니다. 재개할 때 해당 디렉토리의 세션만 표시됩니다.</p><p>Claude는 현재 브랜치의 파일을 봅니다. 브랜치를 전환하면 Claude는 새 브랜치의 파일을 보지만, 대화 이력은 동일하게 유지됩니다. 전환 후에도 Claude는 논의한 내용을 기억합니다.</p><p>세션이 디렉토리에 연결되므로, 개별 브랜치를 위한 별도의 디렉토리를 생성하는 <a href="/claude-code-docs-ko/common-workflows.html#run-parallel-claude-code-sessions-with-git-worktrees">git worktrees</a>를 사용하여 병렬 Claude 세션을 실행할 수 있습니다.</p><h3 id="세션-재개-또는-포크" tabindex="-1">세션 재개 또는 포크 <a class="header-anchor" href="#세션-재개-또는-포크" aria-label="Permalink to &quot;세션 재개 또는 포크&quot;">​</a></h3><p><code>claude --continue</code> 또는 <code>claude --resume</code>으로 세션을 재개하면, 동일한 세션 ID를 사용하여 중단한 곳에서 계속합니다. 새 메시지가 기존 대화에 추가됩니다. 전체 대화 이력은 복원되지만, 세션 범위 권한은 복원되지 않습니다. 다시 승인해야 합니다.</p><p>원본 세션에 영향을 주지 않고 다른 접근 방식을 시도하려면 <code>--fork-session</code> 플래그를 사용하세요:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">claude</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --continue</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --fork-session</span></span></code></pre></div><p>이렇게 하면 해당 시점까지의 대화 이력을 보존하면서 새 세션 ID를 생성합니다. 원본 세션은 변경되지 않습니다. 재개와 마찬가지로, 포크된 세션은 세션 범위 권한을 상속하지 않습니다.</p><p><strong>여러 터미널에서 동일한 세션</strong>: 여러 터미널에서 동일한 세션을 재개하면, 두 터미널 모두 동일한 세션 파일에 씁니다. 두 사람이 같은 노트북에 쓰는 것처럼 양쪽의 메시지가 인터리브됩니다. 아무것도 손상되지 않지만 대화가 뒤섞입니다. 각 터미널은 세션 중 자신의 메시지만 보지만, 나중에 해당 세션을 재개하면 모든 것이 인터리브된 것을 볼 수 있습니다. 동일한 시작점에서의 병렬 작업의 경우, <code>--fork-session</code>을 사용하여 각 터미널에 고유한 깨끗한 세션을 부여하세요.</p><h3 id="컨텍스트-윈도우" tabindex="-1">컨텍스트 윈도우 <a class="header-anchor" href="#컨텍스트-윈도우" aria-label="Permalink to &quot;컨텍스트 윈도우&quot;">​</a></h3><p>Claude의 컨텍스트 윈도우는 대화 이력, 파일 내용, 명령 출력, <a href="/claude-code-docs-ko/memory.html">CLAUDE.md</a>, <a href="/claude-code-docs-ko/memory.html#auto-memory">auto memory</a>, 로드된 skills, 시스템 지침을 보유합니다. 작업하면서 컨텍스트가 채워집니다. Claude가 자동으로 압축하지만, 대화 초기의 지침은 손실될 수 있습니다. 영구 규칙은 CLAUDE.md에 넣고, <code>/context</code>를 실행하여 공간 사용 상태를 확인하세요.</p><p>컨텍스트 윈도우에 무엇이 로드되고 언제 로드되는지에 대한 대화형 안내는 <a href="/claude-code-docs-ko/context-window.html">컨텍스트 윈도우 탐색</a>을 참조하세요.</p><h4 id="컨텍스트가-가득-찬-경우" tabindex="-1">컨텍스트가 가득 찬 경우 <a class="header-anchor" href="#컨텍스트가-가득-찬-경우" aria-label="Permalink to &quot;컨텍스트가 가득 찬 경우&quot;">​</a></h4><p>Claude Code는 한계에 접근하면 자동으로 컨텍스트를 관리합니다. 먼저 오래된 도구 출력을 지우고, 필요하면 대화를 요약합니다. 요청과 핵심 코드 스니펫은 보존되지만, 대화 초기의 자세한 지침은 손실될 수 있습니다. 대화 이력에 의존하기보다 CLAUDE.md에 영구 규칙을 넣으세요.</p><p>압축 중 보존되는 내용을 제어하려면 CLAUDE.md에 &quot;Compact Instructions&quot; 섹션을 추가하거나 <code>/compact</code>를 포커스와 함께 실행하세요 (예: <code>/compact focus on the API changes</code>).</p><p>단일 파일이나 도구 출력이 너무 커서 각 요약 후 컨텍스트가 즉시 다시 채워지면, Claude Code는 몇 번의 시도 후 자동 압축을 중단하고 루프 대신 오류를 표시합니다. 복구 단계는 <a href="/claude-code-docs-ko/troubleshooting.html#auto-compaction-stops-with-a-thrashing-error">자동 압축이 thrashing 오류로 중단됨</a>을 참조하세요.</p><p><code>/context</code>를 실행하여 공간 사용 상태를 확인하세요. MCP 도구 정의는 기본적으로 지연되며 <a href="/claude-code-docs-ko/mcp.html#scale-with-mcp-tool-search">도구 검색</a>을 통해 필요 시 로드되므로, Claude가 특정 도구를 사용할 때까지 도구 이름만 컨텍스트를 소비합니다. <code>/mcp</code>를 실행하여 서버별 비용을 확인하세요.</p><h4 id="skills-및-하위-에이전트로-컨텍스트-관리" tabindex="-1">skills 및 하위 에이전트로 컨텍스트 관리 <a class="header-anchor" href="#skills-및-하위-에이전트로-컨텍스트-관리" aria-label="Permalink to &quot;skills 및 하위 에이전트로 컨텍스트 관리&quot;">​</a></h4><p>압축 외에도 컨텍스트에 로드되는 내용을 제어하는 다른 기능을 사용할 수 있습니다.</p><p><a href="/claude-code-docs-ko/skills.html">Skills</a>는 필요 시 로드됩니다. Claude는 세션 시작 시 skill 설명을 보지만, skill이 사용될 때만 전체 내용이 로드됩니다. 수동으로 호출하는 skills의 경우, <code>disable-model-invocation: true</code>를 설정하여 필요할 때까지 설명을 컨텍스트에서 제외하세요.</p><p><a href="/claude-code-docs-ko/sub-agents.html">하위 에이전트</a>는 메인 대화와 완전히 분리된 자체 새로운 컨텍스트를 가집니다. 그들의 작업이 여러분의 컨텍스트를 부풀리지 않습니다. 완료되면 요약을 반환합니다. 이 격리가 하위 에이전트가 긴 세션에 도움이 되는 이유입니다.</p><p>각 기능의 비용은 <a href="/claude-code-docs-ko/features-overview.html#understand-context-costs">컨텍스트 비용</a>을, 컨텍스트 관리 팁은 <a href="/claude-code-docs-ko/costs.html#reduce-token-usage">토큰 사용량 줄이기</a>를 참조하세요.</p><h2 id="체크포인트와-권한으로-안전하게-유지" tabindex="-1">체크포인트와 권한으로 안전하게 유지 <a class="header-anchor" href="#체크포인트와-권한으로-안전하게-유지" aria-label="Permalink to &quot;체크포인트와 권한으로 안전하게 유지&quot;">​</a></h2><p>Claude에는 두 가지 안전 메커니즘이 있습니다: 체크포인트로 파일 변경을 취소하고, 권한으로 Claude가 묻지 않고 할 수 있는 것을 제어합니다.</p><h3 id="체크포인트로-변경-사항-취소" tabindex="-1">체크포인트로 변경 사항 취소 <a class="header-anchor" href="#체크포인트로-변경-사항-취소" aria-label="Permalink to &quot;체크포인트로 변경 사항 취소&quot;">​</a></h3><p><strong>모든 파일 편집은 되돌릴 수 있습니다.</strong> Claude가 파일을 편집하기 전에 현재 내용의 스냅샷을 만듭니다. 문제가 발생하면 <code>Esc</code>를 두 번 눌러 이전 상태로 되감거나, Claude에게 취소를 요청하세요.</p><p>체크포인트는 git과 별도로 세션에 로컬입니다. 파일 변경만 다룹니다. 원격 시스템(데이터베이스, API, 배포)에 영향을 미치는 작업은 체크포인트할 수 없으며, 이것이 Claude가 외부 부작용이 있는 명령을 실행하기 전에 묻는 이유입니다.</p><h3 id="claude가-할-수-있는-것-제어" tabindex="-1">Claude가 할 수 있는 것 제어 <a class="header-anchor" href="#claude가-할-수-있는-것-제어" aria-label="Permalink to &quot;Claude가 할 수 있는 것 제어&quot;">​</a></h3><p><code>Shift+Tab</code>을 눌러 권한 모드를 순환하세요:</p><ul><li><strong>기본값</strong>: Claude가 파일 편집과 셸 명령 전에 묻습니다</li><li><strong>편집 자동 수락</strong>: Claude가 프롬프트 없이 파일을 편집하고 <code>mkdir</code>, <code>mv</code> 같은 일반적인 파일 시스템 명령을 실행합니다. 다른 명령은 여전히 묻습니다</li><li><strong>플랜 모드</strong>: Claude가 읽기 전용 도구만 사용하여 실행 전에 승인할 수 있는 계획을 생성합니다</li><li><strong>Auto 모드</strong>: Claude가 백그라운드 안전 검사로 모든 작업을 평가합니다. 현재 리서치 프리뷰입니다</li></ul><p><code>.claude/settings.json</code>에서 특정 명령을 허용하여 Claude가 매번 묻지 않도록 할 수도 있습니다. <code>npm test</code>나 <code>git status</code> 같은 신뢰하는 명령에 유용합니다. 설정은 조직 전체 정책에서 개인 선호도까지 범위를 지정할 수 있습니다. 자세한 내용은 <a href="/claude-code-docs-ko/permissions.html">권한</a>을 참조하세요.</p><hr><h2 id="claude-code와-효과적으로-작업하기" tabindex="-1">Claude Code와 효과적으로 작업하기 <a class="header-anchor" href="#claude-code와-효과적으로-작업하기" aria-label="Permalink to &quot;Claude Code와 효과적으로 작업하기&quot;">​</a></h2><p>이 팁들은 Claude Code에서 더 나은 결과를 얻는 데 도움이 됩니다.</p><h3 id="claude-code에-도움-요청" tabindex="-1">Claude Code에 도움 요청 <a class="header-anchor" href="#claude-code에-도움-요청" aria-label="Permalink to &quot;Claude Code에 도움 요청&quot;">​</a></h3><p>Claude Code는 사용 방법을 가르쳐 줄 수 있습니다. &quot;hooks는 어떻게 설정하나요?&quot; 또는 &quot;CLAUDE.md를 구조화하는 가장 좋은 방법은?&quot;과 같은 질문을 하면 Claude가 설명해 줍니다.</p><p>내장 명령도 설정을 안내합니다:</p><ul><li><code>/init</code>은 프로젝트의 CLAUDE.md 생성을 안내합니다</li><li><code>/agents</code>는 커스텀 하위 에이전트 구성을 도와줍니다</li><li><code>/doctor</code>는 설치의 일반적인 문제를 진단합니다</li></ul><h3 id="대화입니다" tabindex="-1">대화입니다 <a class="header-anchor" href="#대화입니다" aria-label="Permalink to &quot;대화입니다&quot;">​</a></h3><p>Claude Code는 대화형입니다. 완벽한 프롬프트가 필요하지 않습니다. 원하는 것으로 시작한 다음 개선하세요:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>로그인 버그를 수정해줘</span></span></code></pre></div><p>[Claude가 조사하고 시도]</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>정확하지 않아. 문제는 세션 처리에 있어.</span></span></code></pre></div><p>[Claude가 접근 방식 조정]</p><p>첫 시도가 맞지 않을 때, 처음부터 다시 시작할 필요가 없습니다. 반복하면 됩니다.</p><h4 id="중단하고-방향-전환" tabindex="-1">중단하고 방향 전환 <a class="header-anchor" href="#중단하고-방향-전환" aria-label="Permalink to &quot;중단하고 방향 전환&quot;">​</a></h4><p>언제든지 Claude를 중단할 수 있습니다. 잘못된 방향으로 가고 있다면, 수정 사항을 입력하고 Enter를 누르세요. Claude는 하던 것을 중단하고 여러분의 입력에 따라 접근 방식을 조정합니다. 끝날 때까지 기다리거나 다시 시작할 필요가 없습니다.</p><h3 id="처음부터-구체적으로" tabindex="-1">처음부터 구체적으로 <a class="header-anchor" href="#처음부터-구체적으로" aria-label="Permalink to &quot;처음부터 구체적으로&quot;">​</a></h3><p>초기 프롬프트가 정확할수록 수정이 적게 필요합니다. 특정 파일을 참조하고, 제약 조건을 언급하고, 예제 패턴을 가리키세요.</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>만료된 카드를 가진 사용자의 결제 흐름이 깨졌어.</span></span>
<span class="line"><span>src/payments/에서 문제를 확인해줘, 특히 토큰 갱신 부분.</span></span>
<span class="line"><span>먼저 실패하는 테스트를 작성하고, 그 다음 수정해줘.</span></span></code></pre></div><p>모호한 프롬프트도 작동하지만, 방향 전환에 더 많은 시간이 걸립니다. 위와 같은 구체적인 프롬프트는 종종 첫 시도에 성공합니다.</p><h3 id="claude에게-검증할-것을-제공" tabindex="-1">Claude에게 검증할 것을 제공 <a class="header-anchor" href="#claude에게-검증할-것을-제공" aria-label="Permalink to &quot;Claude에게 검증할 것을 제공&quot;">​</a></h3><p>Claude는 자신의 작업을 확인할 수 있을 때 더 잘 수행합니다. 테스트 케이스를 포함하거나, 예상 UI의 스크린샷을 붙여넣거나, 원하는 출력을 정의하세요.</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>validateEmail을 구현해줘. 테스트 케이스: &#39;user@example.com&#39; → true,</span></span>
<span class="line"><span>&#39;invalid&#39; → false, &#39;user@.com&#39; → false. 끝나면 테스트를 실행해줘.</span></span></code></pre></div><p>시각적 작업의 경우, 디자인 스크린샷을 붙여넣고 Claude에게 구현과 비교하도록 요청하세요.</p><h3 id="구현-전에-탐색" tabindex="-1">구현 전에 탐색 <a class="header-anchor" href="#구현-전에-탐색" aria-label="Permalink to &quot;구현 전에 탐색&quot;">​</a></h3><p>복잡한 문제의 경우, 조사와 코딩을 분리하세요. 플랜 모드(<code>Shift+Tab</code> 두 번)를 사용하여 먼저 코드베이스를 분석하세요:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>src/auth/를 읽고 세션을 어떻게 처리하는지 이해해줘.</span></span>
<span class="line"><span>그 다음 OAuth 지원을 추가하는 계획을 만들어줘.</span></span></code></pre></div><p>계획을 검토하고, 대화를 통해 개선한 다음, Claude가 구현하도록 하세요. 이 두 단계 접근 방식은 바로 코드로 뛰어드는 것보다 더 나은 결과를 만듭니다.</p><h3 id="지시하지-말고-위임" tabindex="-1">지시하지 말고 위임 <a class="header-anchor" href="#지시하지-말고-위임" aria-label="Permalink to &quot;지시하지 말고 위임&quot;">​</a></h3><p>유능한 동료에게 위임한다고 생각하세요. 컨텍스트와 방향을 제공한 다음 Claude가 세부 사항을 파악하도록 신뢰하세요:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>만료된 카드를 가진 사용자의 결제 흐름이 깨졌어.</span></span>
<span class="line"><span>관련 코드는 src/payments/에 있어. 조사하고 수정해줄 수 있어?</span></span></code></pre></div><p>어떤 파일을 읽거나 어떤 명령을 실행할지 지정할 필요가 없습니다. Claude가 알아서 합니다.</p><h2 id="다음-단계" tabindex="-1">다음 단계 <a class="header-anchor" href="#다음-단계" aria-label="Permalink to &quot;다음 단계&quot;">​</a></h2><ul><li><a href="/claude-code-docs-ko/features-overview.html">기능으로 확장하기</a>: Skills, MCP 연결, 커스텀 명령 추가</li><li><a href="/claude-code-docs-ko/common-workflows.html">일반적인 워크플로우</a>: 일반적인 작업에 대한 단계별 가이드</li></ul>`,102)])])}const C=a(l,[["render",s]]);export{p as __pageData,C as default};
